Aktiver dit Lunar-kort

/* Global */
* {
font-family: helvetica, arial, sans-serif;
}

img {
max-width: 100%;
}

/* Container */
.content {
color: #293e52;
font-size: 14px;

overflow-y: hidden;
margin-bottom: 40px;
}

/* Footer */
.footer > span {
display: block;
}

.footer > a,
span {
text-align: center;

font-weight: 400;
letter-spacing: -0.03em;
}

.footer-title,
.footer-title > a {
color: #4b5863;

font-size: 13px;
line-height: 15px;
}

.footer-sub-title {
color: #919ea8;
margin-top: 8px;

font-size: 12px;
line-height: 14px;
}

